<?php if ( ! defined('BASEPATH')) exit('No direct script access allowed');Class Laporan_Pengeluaran extends CI_Controller { 	function __construct(){ 		parent::__construct(); 				$this->data_request = $_REQUEST;				$module = $this->router->module;		$directory = $this->router->directory;		$class = $this->router->class;		$method = $this->router->method;		$directory = trim(str_replace('../modules/'.$module ,'',str_replace('/controllers/','',$directory)),'/');				$this->module = $module;		if(trim($directory) != ''){			$this->directory = $directory;		} else {			$this->directory = '0';			$this->directory2 = '';		}		$this->class = $class;		$this->method = $method;	}			function pengeluaran_table(){				$field = array();		$field['r1'] = array('sc' => 'r1','ctype' => 'text', 'bypassvalue' => '', 'title' => 'DOK BC');		$field['r2'] = array('sc' => 'r2','ctype' => 'text', 'bypassvalue' => '', 'title' => 'NO');		$field['r3'] = array('sc' => 'r3','ctype' => 'text', 'bypassvalue' => '', 'title' => 'TANGGAL');		$field['r4'] = array('sc' => 'r4','ctype' => 'text', 'bypassvalue' => '', 'title' => 'NO');		$field['r5'] = array('sc' => 'r5','ctype' => 'text', 'bypassvalue' => '', 'title' => 'TANGGAL');		$field['r6'] = array('sc' => 'r6','ctype' => 'text', 'bypassvalue' => '', 'title' => 'SUPPLIER NAME');		$field['r7'] = array('sc' => 'r7','ctype' => 'text', 'bypassvalue' => '', 'title' => 'KANTOR BC');		$field['r10'] = array('sc' => 'r10','ctype' => 'text', 'bypassvalue' => '', 'title' => 'VALAS');		$field['r11'] = array('sc' => 'r11','ctype' => 'text', 'bypassvalue' => '', 'title' => 'AMOUNT');		$field['r14'] = array('sc' => 'r14','ctype' => 'text', 'bypassvalue' => '', 'title' => 'NETTO');				//$field['r5'] = array('sc' => 'r5','ctype' => 'text', 'bypassvalue' => '', 'title' => 'AMOUNT', 'data_type' => 'decimal', 'decimal_digit' => 4);		//$field['r8'] = array('sc' => 'r6','ctype' => 'int', 'bypassvalue' => '', 'title' => 'NILAI', 'data_type' => 'decimal', 'decimal_digit' => 4);				return $field;	}		function index(){		$this->load->model('main');		$component['loadlayout'] = true;		$component['view_load'] = 'internal_report/laporan_pengeluaran/view';		$component['load_js'][] = 'internal_report/laporan_pengeluaran/view';				$component['page_title'] = "Laporan Bulanan Pengeluaran";		$dashboard_table = array();	     	  // $field = $this->rpt_barang_jadi_table();		$field = $this->pengeluaran_table();				$dashboard_table['field'] = $field;		//var_dump($dashboard_table);		$component['dashboard_table'] = $dashboard_table;				$this->authentication->ajaxlayout($component);	}		function loaddata(){		//var_dump($_REQUEST);die();		//print_r("cccc");				$field = $this->pengeluaran_table();				$date_start = isset($_REQUEST['date_start']) ?  $_REQUEST['date_start'] : '';		$date_end = isset($_REQUEST['date_end']) ? $_REQUEST['date_end'] : '';		$type_bc_id = isset($_REQUEST['type_bc_id']) ? $_REQUEST['type_bc_id'] : '';		$print = isset($_REQUEST['print']) ? $_REQUEST['print'] : 0;		$format = isset($_REQUEST['format']) ? $_REQUEST['format'] : 'xlsx';		$page = isset($_POST['page'])?$_POST['page']:1; // get the requested page         $rows = isset($_POST['rows'])?$_POST['rows']:10; // get how many rows we want to have into the grid         $sidx = isset($_POST['sidx'])?$_POST['sidx']:'r1'; // get index row - i.e. user click to sort         $sord = isset($_POST['sord'])?$_POST['sord']:'0'; // get the direction 		$search = isset($_REQUEST['_search'])?$_REQUEST['_search']:false; 		$filterRules =  isset($_POST['filters'])?$_POST['filters']:false;		//var_dump($date_end);die();				$limit =  $rows;		$offset =  $rows * ($page - 1);						$order = isset($_REQUEST['order']) ? $_REQUEST['order'] : array();				if($sord == 'asc'){			$sord = 1;		} else {			$sord = 2;		}				$sort =	$sidx. '='.$sord;							if(strlen(trim($date_start)) == 0 ){			$date_start = '1900-01-01';		}				if(strlen(trim($date_end)) == 0 ){			$date_end = '9999-12-31';		}				$return = array();		$return['valid'] = false;		$return['message'] = "Internal Server Error";			//var_dump($print);die();								//$sp = "dbo.sp_rpt_bc_out_old";	   	        // $sp = "dbo.sp_rpt_bahan_baku_accounting";		// $sp = "dbo.sp_rpt_wip_accounting";		  $sp = "dbo.sp_laporan_pengeluaran"; 		if($print == 1){			$this->rpc_service->setSP(array("sp"=> $sp,"mode"=> $print == 1 ? "2" : "1","debug"=>"1"));		} else {			$this->rpc_service->setSP($sp);		}				$this->rpc_service->addField('date_start',$date_start);		$this->rpc_service->addField('date_end',$date_end);		$this->rpc_service->addField('type_id',$type_bc_id);		$this->rpc_service->addField('format',$format);		$this->rpc_service->addField('temp_folder',sys_get_temp_dir());		$this->rpc_service->addField('sort',$sort);		$this->rpc_service->addField('limit',$limit);		$this->rpc_service->addField('offset',$offset);						$this->rpc_service->setWhere($search,$filterRules,$field);		//var_dump($print);die();			if($print == 1){						$result = $this->rpc_service->resultPrint_laporan('','','','',$format,$date_start,$date_end);		    echo json_encode($result);		} else {			$this->authentication->plainlayout();			//var_dump($sp);die();						$result = $this->rpc_service->resultJSON_pop();								$data_result = json_decode($result['data'],true);						if(isset($data_result['detail']['result_count'])){				$records = $data_result['detail']['result_count'];				$total = ceil($data_result['detail']['result_count'] / $limit);			} else {				$records = 0;				$total = 0;			}						$responce = new stdclass();			$responce->page = $page;			$responce->records = $records;			$responce->total = $total;			$i=0; 			if($data_result){				if(isset($data_result['xrow'])){					foreach($data_result['xrow'] as $key=>$value){						foreach ($value as $k => $v) {								if($k=='r11'){								 $v=$this->mainconfig->get_decimal_format($v,4,true);									}																						$responce->rows[$i][$k] = $v;						} 						$i++;					}				}			}		//  var_dump($responce);			echo json_encode($responce);		}	}		function print_laporan_pengeluaran(){		$format = isset($_REQUEST['format']) ? $_REQUEST['format'] : false;		$date_start = isset($_REQUEST['date_start']) ? $_REQUEST['date_start'] : false;		$date_end = isset($_REQUEST['date_end']) ? $_REQUEST['date_end'] : false;		$type_bc_id = isset($_REQUEST['type_bc_id']) ? $_REQUEST['type_bc_id'] : false;		//var_dump($date_start ." dan ".$format);die();		  if ($format =='xlsx'){			$this->print_transfer_excel();  		  }else{			 // var_dump($grn_id);die();			  $this->print_transfer_pdf();		  }		  		//   $return['status_code'] = $grn_id;		//   return $return;	}		function print_transfer_excel(){	   $this->load->library('excel');	   	   $format = isset($_REQUEST['format']) ? $_REQUEST['format'] : false;	   $date_start = isset($_REQUEST['date_start']) ? $_REQUEST['date_start'] : false;	   $date_end = isset($_REQUEST['date_end']) ? $_REQUEST['date_end'] : false;	   $type_bc_id = isset($_REQUEST['type_bc_id']) ? $_REQUEST['type_bc_id'] : false;	   	    $page = isset($_POST['page'])?$_POST['page']:1; // get the requested page         $rows = isset($_POST['rows'])?$_POST['rows']:10; // get how many rows we want to have into the grid         $sidx = isset($_POST['sidx'])?$_POST['sidx']:'r1'; // get index row - i.e. user click to sort         $sord = isset($_POST['sord'])?$_POST['sord']:'0'; // get the direction 		$search = isset($_REQUEST['_search'])?$_REQUEST['_search']:false; 		$filterRules =  isset($_POST['filters'])?$_POST['filters']:false;		//var_dump($date_end);die();				$limit =  $rows;		$offset =  $rows * ($page - 1);						$order = isset($_REQUEST['order']) ? $_REQUEST['order'] : array();				if($sord == 'asc'){			$sord = 1;		} else {			$sord = 2;		}				$sort =	$sidx. '='.$sord;							if(strlen(trim($date_start)) 